"use client";

import { useNavigate } from "react-router-dom";
import { useState } from "react";
import { Utensils, Smartphone, Sofa, ShowerHead, Shirt, Tv, Cookie } from "lucide-react";
import Navbar from "../navbar";
import Footer from "../footer";
import CartSidebarWrapper from "../shopcart/CartSidebarWrapper";

export default function SearchPage() {
    const [isCartOpen, setIsCartOpen] = useState(false);
    const navigate = useNavigate();

    const [cartItems, setCartItems] = useState([
        { id: 1, name: "Be Nice Shower Cream, Perfect Elastic Formula, 450 ml.", price: 109, qty: 1, stock: 5, image: "/images/products/showercream.png", warning: false },
        { id: 2, name: "Protex Lavender Ice Freeze Soap Bar 60 g.", price: 19, qty: 3, stock: 3, image: "/images/products/protex.png", warning: false },
        { id: 3, name: "KFC BamBam BOX Menu TheBox special", price: 159, qty: 1, stock: 20, image: "/images/products/kfc.png", warning: false },
    ]);

    // ฟังก์ชันจัดการตะกร้า
    const addToCart = (product) => {
        setCartItems(prev => {
            const exist = prev.find(item => item.id === product.id);
            if (exist) {
                return prev.map(item =>
                    item.id === product.id ? { ...item, qty: item.qty + 1 } : item
                );
            }
            return [...prev, { ...product, qty: 1 }];
        });
    };

    const increaseQty = (id) => {
        setCartItems(prev =>
            prev.map(item => item.id === id ? { ...item, qty: item.qty + 1 } : item)
        );
    };

    const decreaseQty = (id) => {
        setCartItems(prev =>
            prev.map(item =>
                item.id === id ? { ...item, qty: Math.max(item.qty - 1, 1) } : item
            )
        );
    };

    const removeItem = (id) => {
        setCartItems(prev => prev.filter(item => item.id !== id));
    };

    // หมวดหมู่
    const categories = [
        { name: "Snacks", icon: <Cookie size={18} /> },
        { name: "Food & Drink", icon: <Utensils size={18} /> },
        { name: "Smartphone", icon: <Smartphone size={18} /> },
        { name: "Furniture", icon: <Sofa size={18} /> },
        { name: "Shower", icon: <ShowerHead size={18} /> },
        { name: "Clothing", icon: <Shirt size={18} /> },
        { name: "Electronics", icon: <Tv size={18} /> },
    ];

    // สินค้า
    const products = Array(8).fill({
        id: 1,
        name: "KFC BamBam BOX",
        desc: "Menu TheBox special",
        price: 159,
        image: "/images/products/kfc.png",
        category: "Food & Drink"
    });

    return (
        <div className="font-sans bg-white relative">
            <div className={`${isCartOpen ? "blur-sm pointer-events-none" : ""} transition-all duration-300`}>
                {/* Navbar */}
                <Navbar cartItems={cartItems} onCartOpen={() => setIsCartOpen(true)} />

                {/* Main content */}
                <main className={`${isCartOpen ? "blur-sm" : ""}`}>
                    <div className="min-h-screen">
                        {/* Breadcrumb */}
                        <div className="max-w-7xl mx-auto px-6 py-4 text-sm text-gray-500">
                            <span
                                className="cursor-pointer hover:text-green-600"
                                onClick={() => navigate("/")}
                            >
                                Home
                            </span>{" "}
                            / Search
                        </div>

                        {/* Content Layout */}
                        <div className="max-w-7xl mx-auto px-6 grid grid-cols-1 lg:grid-cols-4 gap-6">
                            {/* Sidebar (Filters) */}
                            <aside className="bg-gray-50 p-4 rounded-lg shadow-sm h-fit">
                                <h2 className="font-semibold mb-3">Categories</h2>
                                <ul className="space-y-2 text-sm text-gray-700">
                                    <li><label><input type="checkbox" className="mr-2" />Food & Drink</label></li>
                                    <li><label><input type="checkbox" className="mr-2" />Electronics</label></li>
                                    <li><label><input type="checkbox" className="mr-2" />Clothing</label></li>
                                    <li><label><input type="checkbox" className="mr-2" />Health & Beauty</label></li>
                                </ul>

                                <h2 className="font-semibold mt-6 mb-3">Price Range</h2>
                                <div className="flex items-center space-x-2">
                                    <input type="number" placeholder="Min" className="w-20 px-2 py-1 border rounded" />
                                    <span>-</span>
                                    <input type="number" placeholder="Max" className="w-20 px-2 py-1 border rounded" />
                                </div>
                            </aside>

                            {/* Products Grid */}
                            <section className="lg:col-span-3">
                                <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                                    {/* ตัวอย่าง product card */}
                                    <div className="border rounded-lg shadow-sm p-3 flex flex-col items-center">
                                        <img src="/images/products/kfc.png" alt="KFC" className="w-24 h-24 object-contain" />
                                        <h3 className="text-sm font-medium mt-2 text-center">KFC BamBam BOX</h3>
                                        <p className="text-green-600 font-semibold mt-1">$159</p>
                                        <button className="mt-2 px-3 py-1 bg-green-600 text-white text-xs rounded hover:bg-green-700">
                                            Add to cart
                                        </button>
                                    </div>
                                    {/* ...map เพิ่มได้ */}
                                </div>

                                {/* Pagination */}
                                <div className="flex justify-center mt-6 space-x-2">
                                    <button className="px-3 py-1 border rounded">1</button>
                                    <button className="px-3 py-1 border rounded bg-green-600 text-white">2</button>
                                    <button className="px-3 py-1 border rounded">3</button>
                                </div>
                            </section>
                        </div>
                    </div>
                </main>

                {/* Footer */}
                <Footer />
            </div>

            {/* Cart Sidebar */}
            <CartSidebarWrapper
                isCartOpen={isCartOpen}
                onClose={() => setIsCartOpen(false)}
                cartItems={cartItems}
                increaseQty={increaseQty}
                decreaseQty={decreaseQty}
                removeItem={removeItem}
            />
        </div>
    );
}
